import{_ as e,o as s,c as t,a2 as r}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Arquitectura interna","description":"","frontmatter":{},"headers":[],"relativePath":"bases-de-datos/postgresql/11-arquitectura-interna.md","filePath":"bases-de-datos/postgresql/11-arquitectura-interna.md","lastUpdated":1782521464000}'),i={name:"bases-de-datos/postgresql/11-arquitectura-interna.md"};function n(o,a,l,c,d,p){return s(),t("div",null,[...a[0]||(a[0]=[r(`<h1 id="arquitectura-interna" tabindex="-1">Arquitectura interna <a class="header-anchor" href="#arquitectura-interna" aria-label="Permalink to &quot;Arquitectura interna&quot;">​</a></h1><p>PostgreSQL no es solo un binario que acepta SQL. Por dentro coordina procesos, memoria compartida, archivos de datos, WAL, autovacuum, locks y un optimizador de consultas.</p><h2 id="diagrama-general" tabindex="-1">Diagrama general <a class="header-anchor" href="#diagrama-general" aria-label="Permalink to &quot;Diagrama general&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  A[&quot;Cliente / driver&quot;] --&gt; B[&quot;Postmaster&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  B --&gt; C[&quot;Backend process por conexion&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C --&gt; D[&quot;Parser&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  D --&gt; E[&quot;Rewriter&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  E --&gt; F[&quot;Planner&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  F --&gt; G[&quot;Executor&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  G --&gt; H[&quot;Shared buffers&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  H --&gt; I[&quot;Data files&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  G --&gt; J[&quot;WAL buffers&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  J --&gt; K[&quot;WAL files&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  L[&quot;Autovacuum workers&quot;] --&gt; I</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  M[&quot;Checkpointer&quot;] --&gt; I</span></span></code></pre></div><h2 id="postmaster-y-procesos-backend" tabindex="-1">Postmaster y procesos backend <a class="header-anchor" href="#postmaster-y-procesos-backend" aria-label="Permalink to &quot;Postmaster y procesos backend&quot;">​</a></h2><p>El proceso principal acepta conexiones y crea procesos backend para atender sesiones.</p><p>Cada conexion consume recursos. Por eso, en aplicaciones reales se usa un pool como PgBouncer o el pool del framework.</p><h2 id="parser-rewriter-planner-y-executor" tabindex="-1">Parser, rewriter, planner y executor <a class="header-anchor" href="#parser-rewriter-planner-y-executor" aria-label="Permalink to &quot;Parser, rewriter, planner y executor&quot;">​</a></h2><p>Flujo de una consulta:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SQL -&gt; parse -&gt; rewrite -&gt; plan -&gt; execute -&gt; rows</span></span></code></pre></div><ul><li><strong>Parser:</strong> valida sintaxis.</li><li><strong>Rewriter:</strong> aplica reglas y vistas.</li><li><strong>Planner:</strong> elige plan de ejecucion.</li><li><strong>Executor:</strong> ejecuta el plan.</li></ul><h2 id="shared-buffers" tabindex="-1">Shared buffers <a class="header-anchor" href="#shared-buffers" aria-label="Permalink to &quot;Shared buffers&quot;">​</a></h2><p><code>shared_buffers</code> es una zona de memoria compartida donde PostgreSQL cachea paginas de datos.</p><p>Si una pagina esta en memoria, se evita leer del disco. Si no esta, se carga desde los archivos de datos.</p><h2 id="wal" tabindex="-1">WAL <a class="header-anchor" href="#wal" aria-label="Permalink to &quot;WAL&quot;">​</a></h2><p>Antes de confirmar cambios en datos, PostgreSQL escribe informacion suficiente en el Write-Ahead Log para poder recuperar consistencia tras fallos.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cambio -&gt; WAL -&gt; commit -&gt; data files mas tarde</span></span></code></pre></div><h2 id="background-processes" tabindex="-1">Background processes <a class="header-anchor" href="#background-processes" aria-label="Permalink to &quot;Background processes&quot;">​</a></h2><p>Procesos importantes:</p><ul><li><strong>checkpointer:</strong> fuerza escritura de datos sucios.</li><li><strong>background writer:</strong> ayuda a escribir paginas modificadas.</li><li><strong>walwriter:</strong> escribe WAL buffers.</li><li><strong>autovacuum launcher/workers:</strong> limpian versiones antiguas y actualizan estadisticas.</li><li><strong>stats collector / shared stats:</strong> metricas internas.</li></ul><h2 id="archivos-de-datos" tabindex="-1">Archivos de datos <a class="header-anchor" href="#archivos-de-datos" aria-label="Permalink to &quot;Archivos de datos&quot;">​</a></h2><p>Las tablas e indices se almacenan como archivos en el data directory. El usuario no debe modificarlos manualmente.</p><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Usa pool de conexiones.</li><li>Monitoriza conexiones activas.</li><li>Entiende si un problema es CPU, I/O, locks o memoria.</li><li>No ajustes parametros globales sin medir.</li><li>Revisa logs y vistas <code>pg_stat_*</code>.</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><ul><li>Abrir cientos de conexiones directas.</li><li>Pensar que <code>shared_buffers</code> debe usar toda la RAM.</li><li>Ignorar WAL en estrategias de backup.</li><li>No entender el papel de autovacuum.</li></ul>`,26)])])}const g=e(i,[["render",n]]);export{h as __pageData,g as default};
